<?php
$pageTitle='Picking & Packing';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('picking_packing');
$pdo=getDB();
$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();$picks=$pdo->query('SELECT p.*,w.warehouse_name FROM '.table('picking_lists').' p LEFT JOIN '.table('warehouses').' w ON w.id=p.warehouse_id ORDER BY p.created_at DESC LIMIT 100')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='pick'){createPickingList($pdo,trim((string)$_POST['source_type']),(int)$_POST['source_id'],(int)$_POST['warehouse_id']);flash('success','Picking list created.');}elseif($action==='item'){$pdo->prepare('INSERT INTO '.table('picking_list_items').' (picking_list_id,product_id,required_qty,picked_qty,status) VALUES (?,?,?,0,"pending")')->execute([(int)$_POST['picking_list_id'],(int)$_POST['product_id'],max(0,(float)$_POST['required_qty'])]);flash('success','Pick item added.');}elseif($action==='pack'){$num=nextScopedDocumentNumber($pdo,'packing_slip',setting('packing_prefix','PACK'),operationalScope($pdo));$user=currentUser();$pdo->prepare('INSERT INTO '.table('packing_slips').' (packing_number,picking_list_id,source_type,source_id,status,packed_by,packed_at,package_count,weight_kg,notes) VALUES (?,?,?,?, "packed", ?, NOW(), ?, ?, ?)')->execute([$num,(int)$_POST['picking_list_id'],'pick',(int)$_POST['picking_list_id'],(int)($user['id']??0)?:null,max(1,(int)$_POST['package_count']),max(0,(float)$_POST['weight_kg']),trim((string)$_POST['notes'])]);$pdo->prepare('UPDATE '.table('picking_lists').' SET status="packed",picked_at=NOW() WHERE id=?')->execute([(int)$_POST['picking_list_id']]);flash('success','Packing slip created.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'picking-packing']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/picking-packing.php');}
$items=$pdo->query('SELECT i.*,p.picking_number,pr.sku,pr.name FROM '.table('picking_list_items').' i LEFT JOIN '.table('picking_lists').' p ON p.id=i.picking_list_id LEFT JOIN '.table('products').' pr ON pr.id=i.product_id ORDER BY i.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Outbound Fulfillment</div><h2 class="h4 mb-1">Picking & Packing</h2><p class="text-secondary mb-0">Create picking lists, add items, and generate packing slips.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/warehouse-dispatch.php"><?php echo t('Dispatch', 'الشحن والتوزيع'); ?></a></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="pick"><h2 class="h5 mb-3">Create Pick</h2><input class="form-control mb-2" name="source_type" value="order"><input class="form-control mb-2" type="number" name="source_id" placeholder="Source ID"><select class="form-select mb-3" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><button class="btn btn-brand w-100">Create Picking List</button></form><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="item"><h2 class="h5 mb-3">Add Pick Item</h2><select class="form-select mb-2" name="picking_list_id"><?php foreach($picks as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['picking_number']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-3" type="number" step="0.0001" name="required_qty" value="1"><button class="btn btn-outline-primary w-100">Add Item</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="pack"><h2 class="h5 mb-3">Create Packing Slip</h2><select class="form-select mb-2" name="picking_list_id"><?php foreach($picks as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['picking_number']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" name="package_count" value="1"><input class="form-control mb-2" type="number" step="0.01" name="weight_kg" placeholder="Weight kg"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-success w-100">Pack</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Picking Lists</h2><table class="table"><thead><tr><th>Pick</th><th>Warehouse</th><th>Source</th><th>Status</th></tr></thead><tbody><?php foreach($picks as $p): ?><tr><td><strong><?php echo esc($p['picking_number']); ?></strong></td><td><?php echo esc($p['warehouse_name']); ?></td><td><?php echo esc($p['source_type'].' #'.$p['source_id']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($p['status'])); ?>"><?php echo esc($p['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Pick Items</h2><table class="table"><thead><tr><th>Pick</th><th>Product</th><th>Required</th><th>Picked</th><th>Status</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['picking_number']); ?></td><td><?php echo esc($i['sku'].' · '.$i['name']); ?></td><td><?php echo number_format((float)$i['required_qty'],4); ?></td><td><?php echo number_format((float)$i['picked_qty'],4); ?></td><td><span class="badge bg-<?php echo esc(statusTone($i['status'])); ?>"><?php echo esc($i['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>